import { createAttributesViewModel } from './attributes.functions.js';
export const createMonstersViewModel = monster => ({ ...monster,
  attributes: createAttributesViewModel(monster.attributes)
});
export const monsterComparer = t => (a, b) => {
  const ma = t(`Monster.${a.name}`, {
    ns: 'common'
  });
  const mb = t(`Monster.${b.name}`, {
    ns: 'common'
  });

  if (ma < mb) {
    return -1;
  }

  if (ma > mb) {
    return 1;
  }

  return 0;
};